const raw = $json.stdout || $json.data || $json.response || '';
const now = new Date().toISOString();
const lines = String(raw).split('\n').map(s => s.trim()).filter(Boolean);
const gitLines = lines.filter(l => !l.startsWith('---') && !l.startsWith('ADMIN_START') && !l.startsWith('checked_at='));
const dirty = gitLines.some(l => /^[MADRCU?]/.test(l));
const diskLine = lines.find(l => /^\/dev\//.test(l)) || '';
const healthy = !dirty;
const status = healthy ? 'Clean' : 'Changes Present';
const emoji = healthy ? '✅' : '⚠️';
const blocks = [ { type: 'header', text: { type: 'plain_text', text: `${emoji} OpenClaw Assistant Admin` } }, { type: 'context', elements: [ { type: 'mrkdwn', text: `*Checked:* ${now}` }, { type: 'mrkdwn', text: `*Status:* ${status}` } ] }, { type: 'divider' }, { type: 'section', text: { type: 'mrkdwn', text: `*Git Status*\n${dirty ? 'Working tree has changes.' : 'Working tree clean.'}` } }, { type: 'section', text: { type: 'mrkdwn', text: `*Disk*\n${diskLine || 'No disk line found.'}` } } ]; return [{ json: { checkedAt: now, status, healthy, slackText: `${emoji} OpenClaw assistant admin: ${status}`, slackBlocks: blocks } }];
